   "file": "tower.zil",
   "line": 37,
   "endLine": 40,
   "source": "<ROUTINE MEMENTO-F ()\n <COND (<VERB? TAKE>\n\t<TELL \"But that would spoil the display!\" CR>)\n       (T <BROCHURE-PSEUDO>)>>"
