  "QUESTIONS": {
   "name": "QUESTIONS",
   "kind": "global",
   "file": "people.zil",
   "line": 209,
   "value": "<LTABLE \"You did read my letter, and not just give it a hasty glance?\" \"Do you wish me to do so before I leave?\" \"Am I right in assuming that you are the well-known young American detective?\" \"Is it a case that brings you to Cornwall?\" \"Have you a theory about the castle ghost?\" \"May I offer one last suggestion?\" \"Are you one of those brutally fascinating American private eyes?\" \"Are there more girl sleuths like you in the States, my dear?\" \"You've seen that room, have you not?\">"
  },
  "RHYMES-WITH-RICH": {
   "name": "RHYMES-WITH-RICH",
   "kind": "global",
   "file": "people.zil",
   "line": 478,
   "value": "\"\"I won't say what I think of her, but it rhymes with 'rich.'\"\""
  },
  "TRESYLLIAN": {
   "name": "TRESYLLIAN",
   "kind": "global",
   "file": "people.zil",
   "line": 586,
   "value": "\"Tresyllian\""
  },
  "WHITISH-GLIMPSE": {
   "name": "WHITISH-GLIMPSE",
   "kind": "global",
   "file": "people.zil",
   "line": 604,
   "value": "\" a glimpse of a whitish figure from the rear\""
  },
  "JACK-THINKS-GLADYS": {
   "name": "JACK-THINKS-GLADYS",
   "kind": "global",
   "file": "people.zil",
   "line": 760,
   "value": "\"\"Dashed if I'm going to have my digestion upset\nby Gladys's whining, the odious little twit!\""
  },
  "LOVER-SAID:FLAG": {
   "name": "LOVER-SAID:FLAG",
   "kind": "global",
   "file": "people.zil",
   "line": 843,
   "value": "<>"
  },
  "MUSTACHE-STORY": {
   "name": "MUSTACHE-STORY",
   "kind": "global",
   "file": "people.zil",
   "line": 1344,
   "value": "\"\"Dear me,\" he giggles nervously, \"I'm afraid you've found out my little\nsecret! A lady friend, you see, begged me to shave off my mustache.\nI did so just before coming to Cornwall. But then I felt so naked without\nit, that I bought a hair piece until I could grow back my own.\"|\""
  },
  "GLASSES-FOR": {
   "name": "GLASSES-FOR",
   "kind": "global",
   "file": "people.zil",
   "line": 1491,
   "value": "\" glasses for closeup art work\""
  },
